+        let mut out = String::new();
+        let width = buffer.area.width;
+        let height = buffer.area.height;
+        for y in 0..height {
+            for x in 0..width {
+                if let Some(cell) = buffer.cell((x, y)) {
+                    out.push_str(cell.symbol());
+                } else {
+                    out.push(' ');
+                }
+            }
+            out.push('\n');
+        }
+        out
+    }
